    const { verifier, challenge } = await generatePkcePair();
    const state = generateRandomString(32);
    const nonce = generateRandomString(32);

    // Store PKCE verifier, state, and nonce in session storage
    sessionStorage.setItem('pkce_code_verifier', verifier);
    sessionStorage.setItem('oauth_state', state);
    sessionStorage.setItem('oauth_nonce', nonce);

    const authUrl = new URL(OIDC_CONFIG.AUTHORIZATION_ENDPOINT);
    authUrl.searchParams.append('client_id', OIDC_CONFIG.CLIENT_ID);
    authUrl.searchParams.append('redirect_uri', OIDC_CONFIG.REDIRECT_URI);
    authUrl.searchParams.append('response_type', OIDC_CONFIG.RESPONSE_TYPE);
    authUrl.searchParams.append('scope', OIDC_CONFIG.SCOPE);
